import React, { useState } from "react";
import { useSocket } from "./hooks/useSocket";
import TopBar from "./components/TopBar";
import Sidebar from "./components/Sidebar";
import Terminal from "./components/Terminal";
import HostnameModal from "./components/HostnameModal";

export default function App() {
  const { connected, deviceState, outputLines, prompt, sendCommand } = useSocket();
  const [modal, setModal] = useState(false);

  const handleHostname = (name) => {
    sendCommand("configure terminal");
    setTimeout(() => { sendCommand(`hostname ${name}`); setTimeout(() => sendCommand("end"), 200); }, 200);
    setModal(false);
  };

  return (
    <div style={{ minHeight:"100vh", background:"#f8fafc", display:"flex", flexDirection:"column", fontFamily:"monospace" }}>
      <TopBar device={deviceState} connected={connected} onHostnameClick={()=>setModal(true)} />
      <div style={{ display:"flex", flex:1, overflow:"hidden", height:"calc(100vh - 65px)" }}>
        <Sidebar onCommand={sendCommand} deviceState={deviceState} />
        <Terminal outputLines={outputLines} prompt={prompt} onCommand={sendCommand} />
      </div>
      {modal && <HostnameModal current={deviceState?.hostname||"Switch1"} onApply={handleHostname} onClose={()=>setModal(false)} />}
      <style>{`*{box-sizing:border-box}::-webkit-scrollbar{width:6px}::-webkit-scrollbar-track{background:#f1f5f9}::-webkit-scrollbar-thumb{background:#cbd5e1;border-radius:3px}`}</style>
    </div>
  );
}
